DOMAIN_CONFIGS = {
    "finance": {"entries": FINANCE_QUERIES, "answer_prefix": "Financial"},
    "legal": {"entries": LEGAL_QUERIES, "answer_prefix": "Legal"},
    "healthcare": {"entries": HEALTHCARE_QUERIES, "answer_prefix": "Healthcare"},
    "technology": {"entries": TECHNOLOGY_QUERIES, "answer_prefix": "Technology"},
    "general": {"entries": GENERAL_QUERIES, "answer_prefix": "General"},
}

_generated_datasets: Dict[str, List[GoldDatasetEntry]] = {}


def generate_dataset(domain: str) -> List[GoldDatasetEntry]:
    config = DOMAIN_CONFIGS.get(domain)
    if config is None:
        return []
    entries: List[GoldDatasetEntry] = []
    for i, q in enumerate(config["entries"]):
        entry = GoldDatasetEntry(
            query_id=f"{domain}-{i+1:04d}",
            question=q["question"],
            answer=f"{config['answer_prefix']} answer for: {q['question']}",
            relevant_docs=q.get("relevant_docs", []),
            difficulty=q.get("difficulty", "simple"),
            domain=domain,
        )
        entries.append(entry)
    return entries


def generate_all_datasets() -> Dict[str, List[GoldDatasetEntry]]:
    global _generated_datasets
    if not _generated_datasets:
        for domain in DOMAIN_CONFIGS:
            _generated_datasets[domain] = generate_dataset(domain)
    return _generated_datasets


def get_dataset(domain: str) -> List[GoldDatasetEntry]:
    datasets = generate_all_datasets()
    return datasets.get(domain, [])


def list_datasets() -> List[str]:
    return sorted(DOMAIN_CONFIGS.keys())


def total_queries() -> int:
    return sum(len(qs) for qs in generate_all_datasets().values())
